import pytest
from your_module import topological_sort  # Replace with your actual module name


def is_valid_topological_sort(graph: dict, sorted_order: list) -> bool:
    """Verify if the sorted order is a valid topological sort for the input graph."""
    position_map = {node: idx for idx, node in enumerate(sorted_order)}

    # Check all nodes in the original graph exist in the sorted list
    for node in graph:
        if node not in position_map:
            return False

        # Validate all edges point from earlier to later in the sorted list
        for neighbor in graph[node]:
            if neighbor not in position_map:
                return False
            if position_map[node] >= position_map[neighbor]:
                return False
    return True


# ------------------------------ Happy Path Tests ------------------------------
def test_empty_graph():
    """Test sorting an empty directed graph."""
    assert topological_sort({}) == []
    assert is_valid_topological_sort({}, [])


def test_single_node():
    """Test sorting a graph with only one node."""
    graph = {"start": []}
    result = topological_sort(graph)
    assert result == ["start"]
    assert is_valid_topological_sort(graph, result)


def test_single_directed_edge():
    """Test sorting a graph with one single directed edge."""
    graph = {"a": ["b"], "b": []}
    result = topological_sort(graph)
    assert is_valid_topological_sort(graph, result)
    # Confirm core dependency order is maintained
    assert result[0] == "a" and result[1] == "b"


def test_linear_chain():
    """Test sorting a linear directed chain graph."""
    graph = {1: [2], 2: [3], 3: [4], 4: []}
    result = topological_sort(graph)
    assert is_valid_topological_sort(graph, result)
    assert result == [1, 2, 3, 4]


def test_complex_dag():
    """Test sorting the classic multi-parent DAG example."""
    # 0 → 1, 0 → 2, 1 →3, 2→3
    graph = {0: [1, 2], 1: [3], 2: [3], 3: []}
    result = topological_sort(graph)
    assert is_valid_topological_sort(graph, result)
    # Ensure root node comes first and final node comes last
    assert result[0] == 0
    assert result[-1] == 3


def test_disconnected_dags():
    """Test sorting a graph with multiple disconnected components."""
    graph = {"A": ["B"], "B": [], "C": ["D"], "D": []}
    result = topological_sort(graph)
    assert is_valid_topological_sort(graph, result)
    # Validate both independent dependency pairs
    assert ("A" in result and "B" in result and result.index("A") < result.index("B"))
    assert ("C" in result and "D" in result and result.index("C") < result.index("D"))


def test_duplicate_edges():
    """Test sorting a graph with duplicate directed edges."""
    graph = {"a": ["b", "b"], "b": []}
    result = topological_sort(graph)
    assert is_valid_topological_sort(graph, result)
    assert result == ["a", "b"]


